mapper.select:
SELECT p.PLC_NO AS plcNo, p.PLC_ID AS plcId, p.PLC_RGN_CD AS plcRgnCd, p.PLC_NAME AS plcName, p.PLC_ADDR AS plcAddr, p.PLC_LAT AS plcLat, p.PLC_LOT AS plcLot, p.PLC_TELNO AS plcTelno, p.PLC_OVERVIEW AS plcOverview, p.PLC_MAIN_IMG_URL AS plcMainImgUrl, p.PLC_THUM_IMG_URL AS plcThumImgUrl, p.PLC_FLT_CD AS plcFltCd, p.PLC_AVG_RATING AS plcAvgRating, p.PLC_REVIEW_CNT AS plcReviewCnt, s.SLEEP_CHECK_IN AS sleepCheckIn, s.SLEEP_CHECK_OUT AS sleepCheckOut, s.SLEEP_INFOCENTER AS sleepInfocenter, s.SLEEP_PARKING AS sleepParking, s.SLEEP_RESERVATION AS sleepReservation, s.SLEEP_RESERVATION_URL AS sleepReservationUrl, s.SLEEP_SUB_FACILITY AS sleepSubFacility, s.SLEEP_BARBECU AS sleepBarbecu, s.SLEEP_BEAUTY AS sleepBeauty, s.SLEEP_BEVERAGE AS sleepBeverage, s.SLEEP_BICYCLE AS sleepBicycle, s.SLEEP_CAMPFIRE AS sleepCampfire, s.SLEEP_FITNESS AS sleepFitness, s.SLEEP_KARAOKE AS sleepKaraoke, s.SLEEP_PUBLIC_BATH AS sleepPublicBath, s.SLEEP_PUBLIC_PC AS sleepPublicPc, s.SLEEP_SAUNA AS sleepSauna, s.SLEEP_SEMINAR AS sleepSeminar, s.SLEEP_SPORTS AS sleepSports FROM PLACE p LEFT JOIN PLACE_SLEEP s ON p.PLC_NO = s.SLEEP_PLC_NO WHERE p.PLC_CAT_CD = 'PLC004'
AND p.PLC_RGN_CD = #{rgnCd}
ORDER BY p.PLC_NO DESC

SELECT p.PLC_NO AS plcNo, p.PLC_ID AS plcId, p.PLC_RGN_CD AS plcRgnCd, p.PLC_NAME AS plcName, p.PLC_ADDR AS plcAddr, p.PLC_FLT_CD AS plcFltCd, p.PLC_AVG_RATING AS plcAvgRating, p.PLC_REVIEW_CNT AS plcReviewCnt, s.SLEEP_CHECK_IN AS sleepCheckIn, s.SLEEP_CHECK_OUT AS sleepCheckOut FROM PLACE p LEFT JOIN PLACE_SLEEP s ON p.PLC_NO = s.SLEEP_PLC_NO WHERE p.PLC_CAT_CD = 'PLC004' AND p.PLC_USE_YN = 'Y'
AND p.PLC_RGN_CD = #{rgnCd}
ORDER BY p.PLC_NO DESC LIMIT #{offset}, #{size}
